import{_ as i,C as h,o,c as l,a5 as a,b as c,w as t,a as d,E as s,a6 as n}from"./chunks/framework._dYbwWGd.js";const A=JSON.parse('{"title":"rebac-authz-webhook","description":"","frontmatter":{},"headers":[],"relativePath":"reference/components/rebac-authz-webhook.md","filePath":"reference/components/rebac-authz-webhook.md"}'),p={name:"reference/components/rebac-authz-webhook.md"};function u(b,e,k,m,f,g){const r=h("Mermaid");return o(),l("div",null,[e[2]||(e[2]=a('<h1 id="rebac-authz-webhook" tabindex="-1">rebac-authz-webhook <a class="header-anchor" href="#rebac-authz-webhook" aria-label="Permalink to &quot;rebac-authz-webhook&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p><code>rebac-authz-webhook</code> connects kcp authorization requests to the relationship-based authorization data Platform Mesh keeps in OpenFGA. It is installed as a Kubernetes authorization webhook and answers <code>SubjectAccessReview</code> requests for kcp logical clusters.</p><p>It is the runtime bridge between the Kubernetes authorization path and the Platform Mesh permission model. Users and service accounts still authenticate through kcp and the identity stack; the webhook contributes authorization decisions based on the OpenFGA stores and tuples maintained by the <a href="./security-operator.html">Security operator</a>.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>This component is in alpha. APIs, request handling, and deployment wiring may change on short notice, including breaking changes.</p></div><h2 id="runtime-role" tabindex="-1">Runtime role <a class="header-anchor" href="#runtime-role" aria-label="Permalink to &quot;Runtime role&quot;">​</a></h2><p>At runtime kcp calls this webhook from its authorization chain. The process runs the <code>serve</code> command, builds a kcp-aware multicluster manager, and serves an HTTPS endpoint at <code>/authz</code>.</p><p>The webhook:</p><ol><li>Receives Kubernetes <code>SubjectAccessReview</code> requests from kcp.</li><li>Identifies the target logical cluster from the request attributes.</li><li>Looks up workspace and organization context through kcp.</li><li>Evaluates permissions against the relevant OpenFGA store.</li><li>Returns an authorization response to kcp.</li></ol><p>The webhook does not create workspaces, users, realms, OpenFGA stores, or authorization models. Those resources are prepared by other Platform Mesh components, especially the <a href="./account-operator.html">Account operator</a> and <a href="./security-operator.html">Security operator</a>.</p><p><code>rebac-authz-webhook</code> does not own any CRDs. At runtime it reads <code>LogicalCluster</code> (<code>core.kcp.io</code>) and <code>Store</code> (<code>core.platform-mesh.io</code>) resources from kcp, and discovers virtual workspace URLs through <code>APIExportEndpointSlice</code>.</p><h2 id="how-it-fits-into-platform-mesh" tabindex="-1">How it fits into Platform Mesh <a class="header-anchor" href="#how-it-fits-into-platform-mesh" aria-label="Permalink to &quot;How it fits into Platform Mesh&quot;">​</a></h2><p>Platform Mesh separates the responsibilities for identity, tenancy, policy storage, and request-time authorization:</p><table tabindex="0"><thead><tr><th>Component</th><th>Role</th></tr></thead><tbody><tr><td><a href="./account-operator.html">Account operator</a></td><td>Creates the account workspace structure in kcp.</td></tr><tr><td><a href="./security-operator.html">Security operator</a></td><td>Creates OpenFGA stores, authorization models, tuples, and identity configuration.</td></tr><tr><td><a href="./openfga.html">OpenFGA</a></td><td>Stores and evaluates relationship-based authorization data.</td></tr><tr><td>kcp</td><td>Receives Kubernetes API requests and calls the authorization webhook.</td></tr><tr><td><code>rebac-authz-webhook</code></td><td>Translates kcp authorization reviews into OpenFGA checks.</td></tr></tbody></table>',14)),(o(),c(n,null,{default:t(()=>[s(r,{id:"mermaid-119",class:"mermaid",graph:"flowchart%20LR%0A%20%20subgraph%20designTime%5B%22Design%20time%22%5D%0A%20%20%20%20securityOperator%5B%22Security%20operator%22%5D%20--%3E%7Cwrites%20stores%2C%20models%2C%20tuples%7C%20fgaStore%5B(%22OpenFGA%20stores%22)%5D%0A%20%20end%0A%0A%20%20subgraph%20runtime%5B%22Runtime%22%5D%0A%20%20%20%20userRequest%5B%22User%20or%20service%20request%22%5D%20--%3E%20kcp%5B%22kcp%20API%20server%22%5D%0A%20%20%20%20kcp%20--%3E%20sar%5B%22SubjectAccessReview%22%5D%0A%20%20%20%20sar%20--%3E%20webhook%5B%22rebac-authz-webhook%20%2Fauthz%22%5D%0A%20%20%20%20webhook%20--%3E%20workspaceContext%5B%22kcp%20workspace%20context%22%5D%0A%20%20%20%20workspaceContext%20--%3E%20fgaCheck%5B(%22OpenFGA%20Check%22)%5D%0A%20%20%20%20fgaCheck%20--%3E%20decision%5B%22Authorization%20response%22%5D%0A%20%20%20%20decision%20--%3E%20kcp%0A%20%20end%0A%0A%20%20fgaStore%20-.read%20by.-%3E%20fgaCheck%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[d(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=a('<h2 id="upstream-concepts-and-dependencies" tabindex="-1">Upstream concepts and dependencies <a class="header-anchor" href="#upstream-concepts-and-dependencies" aria-label="Permalink to &quot;Upstream concepts and dependencies&quot;">​</a></h2><p><code>rebac-authz-webhook</code> depends on these Kubernetes and kcp concepts:</p><table tabindex="0"><thead><tr><th>Concept</th><th>Platform Mesh page</th><th>Role here</th></tr></thead><tbody><tr><td><a href="https://kubernetes.io/docs/reference/access-authn-authz/webhook/" target="_blank" rel="noreferrer">Kubernetes webhook authorization</a></td><td>None</td><td>The HTTPS webhook protocol used by kcp to call <code>/authz</code>.</td></tr><tr><td><a href="https://kubernetes.io/docs/reference/access-authn-authz/authorization/#checking-api-access" target="_blank" rel="noreferrer"><code>SubjectAccessReview</code></a></td><td>None</td><td>Request and response object sent between kcp and the webhook.</td></tr><tr><td><a href="https://kubernetes.io/docs/reference/access-authn-authz/rbac/" target="_blank" rel="noreferrer">Kubernetes RBAC</a></td><td>None</td><td>Used for the management-cluster <code>ClusterRole</code> listed under <a href="#rbac-and-permissions">RBAC and permissions</a>.</td></tr><tr><td><a href="https://docs.kcp.io/kcp/main/concepts/workspaces/" target="_blank" rel="noreferrer">kcp workspaces and logical clusters</a></td><td><a href="./kcp/workspaces.html">kcp workspaces</a></td><td>Each kcp workspace is a logical cluster; the webhook reads <code>LogicalCluster</code> to identify the request&#39;s workspace.</td></tr><tr><td><a href="https://docs.kcp.io/kcp/main/concepts/apis/exporting-apis/" target="_blank" rel="noreferrer">kcp <code>APIExport</code> / <code>APIExportEndpointSlice</code></a></td><td><a href="./kcp/api-sharing.html">API sharing</a></td><td>Used at startup to discover virtual-workspace URLs for per-shard access.</td></tr><tr><td><a href="https://docs.kcp.io/kcp/main/concepts/workspaces/virtual-workspaces/" target="_blank" rel="noreferrer">kcp virtual workspaces</a></td><td><a href="./kcp/virtual-workspaces.html">Virtual workspaces</a></td><td>Per-export endpoints the webhook uses to read kcp resources.</td></tr><tr><td><a href="https://github.com/kubernetes-sigs/multicluster-runtime" target="_blank" rel="noreferrer">multicluster-runtime</a> + <a href="https://github.com/kcp-dev/multicluster-provider" target="_blank" rel="noreferrer">kcp-dev/multicluster-provider</a></td><td><a href="./multicluster-runtime.html">multicluster-runtime</a></td><td>Provide the multicluster manager used to watch kcp logical clusters.</td></tr><tr><td><a href="./kcp-operator.html">kcp-operator</a></td><td><a href="./kcp-operator.html">kcp-operator</a></td><td>Reconciles <code>RootShard</code> and <code>Shard</code> CRs into running kcp shards, including the <code>spec.authorization.webhook</code> configuration that points kcp at this webhook.</td></tr><tr><td><a href="./openfga.html">OpenFGA</a></td><td><a href="./openfga.html">OpenFGA</a></td><td>The relationship-based authorization engine the webhook delegates <code>Check</code> calls to.</td></tr></tbody></table><h2 id="authorization-model" tabindex="-1">Authorization model <a class="header-anchor" href="#authorization-model" aria-label="Permalink to &quot;Authorization model&quot;">​</a></h2><p>The webhook accepts JSON <code>authorization.k8s.io/v1</code> and <code>v1beta1</code> <code>SubjectAccessReview</code> requests and returns the matching <code>SubjectAccessReview</code> response. Platform Mesh&#39;s kcp <code>AuthorizationConfiguration</code> requests <code>subjectAccessReviewVersion: v1</code> (see <a href="./kcp/identity-and-authorization.html">kcp identity and authorization</a>).</p><p>kcp authenticates the caller before invoking the webhook and sends the resulting user in <code>spec.user</code>. The webhook trusts that identity and only decides whether the requested verb and resource are allowed in OpenFGA.</p><p>The authorization path has three high-level cases:</p><table tabindex="0"><thead><tr><th>Case</th><th>What happens</th></tr></thead><tbody><tr><td>Non-resource requests</td><td>This branch is only relevant for clusters that call the webhook without <code>matchConditions</code>. In Platform Mesh&#39;s default kcp config, <code>matchConditions: has(request.resourceAttributes)</code> prevents non-resource SARs from reaching the webhook, and kcp&#39;s <code>AlwaysAllowPaths</code> authorizer runs earlier in the chain. If a cluster does send non-resource SARs to the webhook, paths with a configured prefix (default <code>/api</code>, <code>/openapi</code>, <code>/version</code>) return <code>allowed: true</code>; other non-resource paths get no opinion.</td></tr><tr><td>The <code>root:orgs</code> workspace</td><td>Requests against the parent workspace that hosts all organizations are checked against the shared OpenFGA store named <code>orgs</code>.</td></tr><tr><td>Workspaces under <code>root:orgs</code></td><td>Requests against an organization workspace (for example <code>root:orgs:default</code>) or any account workspace beneath it (for example <code>root:orgs:default:foo</code>) are checked against that organization&#39;s own OpenFGA store.</td></tr></tbody></table><p>The webhook returns <code>allowed: true</code> when OpenFGA authorizes the request. Otherwise it returns <code>allowed: false</code> without setting <code>denied: true</code> (&quot;no opinion&quot;). In Platform Mesh, the webhook is last in the kcp authorizer chain (after RBAC and Node, see <a href="./kcp/identity-and-authorization.html">kcp identity and authorization</a>), so a no-opinion result is effectively a deny.</p><h3 id="workspace-context" tabindex="-1">Workspace context <a class="header-anchor" href="#workspace-context" aria-label="Permalink to &quot;Workspace context&quot;">​</a></h3><p>For account workspaces the webhook keeps a per-logical-cluster cache linking the logical cluster to its organization, account, REST mapping, and OpenFGA store ID. The cache is consulted on every request to evaluate Kubernetes verbs (<code>get</code>, <code>create</code>, <code>list</code>, <code>watch</code>, <code>update</code>, <code>patch</code>, <code>delete</code>) against the correct OpenFGA store.</p><h3 id="relationship-based-checks" tabindex="-1">Relationship-based checks <a class="header-anchor" href="#relationship-based-checks" aria-label="Permalink to &quot;Relationship-based checks&quot;">​</a></h3><p>OpenFGA stores the relationship graph for organizations, accounts, namespaces, and resources. The webhook turns the Kubernetes request into an OpenFGA check using the requesting user, the requested verb, the resource type, and the workspace context. For account workspaces, the request can also include contextual parent relationships so OpenFGA can evaluate inherited permissions.</p><h2 id="kcp-and-openfga-integration" tabindex="-1">kcp and OpenFGA integration <a class="header-anchor" href="#kcp-and-openfga-integration" aria-label="Permalink to &quot;kcp and OpenFGA integration&quot;">​</a></h2><p>The webhook needs access to the root kcp API server for discovery. It reads the <code>APIExportEndpointSlice</code> (default <code>core.platform-mesh.io</code>) from the root API server; the slice enumerates one virtual-workspace URL per kcp shard. The webhook connects to those URLs and uses the multicluster manager (multicluster-runtime + kcp-dev/multicluster-provider) to partition the resulting stream by logical cluster.</p><p>The default endpoint slice name is <code>core.platform-mesh.io</code>. This can be overridden with <code>--kcp-api-export-endpoint-slice-name</code>.</p><h3 id="startup-dependencies" tabindex="-1">Startup dependencies <a class="header-anchor" href="#startup-dependencies" aria-label="Permalink to &quot;Startup dependencies&quot;">​</a></h3><p><code>rebac-authz-webhook</code> reads the following resources at startup. If a required resource is absent, the process exits.</p><table tabindex="0"><thead><tr><th>Resource</th><th>Kind</th><th>Purpose</th></tr></thead><tbody><tr><td><code>core.platform-mesh.io</code> (or value of <code>--kcp-api-export-endpoint-slice-name</code>)</td><td><code>APIExportEndpointSlice</code></td><td>Provides the per-shard virtual-workspace URLs the webhook connects to.</td></tr><tr><td><code>cluster</code> in <code>root:orgs</code></td><td><code>LogicalCluster</code> (<code>core.kcp.io/v1alpha1</code>)</td><td>Self-object for <code>root:orgs</code>; anchors the workspace context cache.</td></tr><tr><td>Store named <code>orgs</code></td><td>OpenFGA store</td><td>Required shared OpenFGA store for <code>root:orgs</code>.</td></tr><tr><td>Per-organization stores</td><td><code>Store</code> (<code>core.platform-mesh.io</code>, in <code>root:orgs</code>)</td><td>Read by the cluster cache; <code>status.storeId</code> routes account-workspace checks to the right OpenFGA store.</td></tr></tbody></table><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="cli-flags" tabindex="-1">CLI flags <a class="header-anchor" href="#cli-flags" aria-label="Permalink to &quot;CLI flags&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Flag</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--metrics-bind-address</code></td><td><code>:9090</code></td><td>Bind address for controller-runtime metrics.</td></tr><tr><td><code>--health-probe-bind-address</code></td><td><code>:8090</code></td><td>Bind address for health and readiness probes.</td></tr><tr><td><code>--openfga-addr</code></td><td><code>openfga.platform-mesh-system:8081</code></td><td>OpenFGA gRPC address.</td></tr><tr><td><code>--webhook-cert-dir</code></td><td><code>config</code></td><td>Directory containing webhook serving certificates. The chart mounts the cert secret at <code>/config</code>, matching this flag&#39;s working directory.</td></tr><tr><td><code>--webhook-cluster-key</code></td><td><code>authorization.kubernetes.io/cluster-name</code></td><td><code>SubjectAccessReview.spec.extra</code> key for the target logical-cluster ID. kcp sets this; the webhook uses it to route OpenFGA checks.</td></tr><tr><td><code>--webhook-allowed-nonresource-prefixes</code></td><td><code>/api</code>, <code>/openapi</code>, <code>/version</code></td><td>Non-resource URL prefixes the webhook allows directly.</td></tr><tr><td><code>--kcp-api-export-endpoint-slice-name</code></td><td><code>core.platform-mesh.io</code></td><td>kcp <code>APIExportEndpointSlice</code> used for logical-cluster discovery.</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p><code>authorization.kubernetes.io/cluster-name</code> is the legacy kcp extra key. It is deprecated as of kcp v0.28.3; the canonical key is <code>authorization.kcp.io/cluster-name</code>. Set <code>--webhook-cluster-key=authorization.kcp.io/cluster-name</code> when running against a kcp version that emits only the canonical key. See the <a href="https://docs.kcp.io/kcp/main/concepts/authorization/authorizers/" target="_blank" rel="noreferrer">kcp webhook authorizer documentation</a>.</p></div><h3 id="environment-variables" tabindex="-1">Environment variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment variables&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>KUBECONFIG</code></td><td>Kubeconfig used by controller-runtime. In the Helm chart this points to <code>/api-kubeconfig/kubeconfig</code> when <code>kcp.kubeconfig.secret</code> is set.</td></tr></tbody></table><h3 id="helm" tabindex="-1">Helm <a class="header-anchor" href="#helm" aria-label="Permalink to &quot;Helm&quot;">​</a></h3><p>The deployment chart is <code>rebac-authz-webhook</code> in <a href="https://github.com/platform-mesh/helm-charts/tree/main/charts/rebac-authz-webhook" target="_blank" rel="noreferrer">platform-mesh/helm-charts</a>. The authoritative values table is generated in the chart README.</p><p>Important defaults:</p><table tabindex="0"><thead><tr><th>Value</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>image.name</code></td><td><code>ghcr.io/platform-mesh/rebac-authz-webhook</code></td><td>Container image.</td></tr><tr><td><code>openfga.url</code></td><td><code>openfga:8081</code></td><td>OpenFGA address passed to <code>--openfga-addr</code>.</td></tr><tr><td><code>kcp.kubeconfig.secret</code></td><td><code>rebac-authz-webhook-kubeconfig</code></td><td>Secret mounted at <code>/api-kubeconfig</code>; must contain key <code>kubeconfig</code>.</td></tr><tr><td><code>service.port</code></td><td><code>9443</code></td><td>HTTPS authorization webhook service port.</td></tr><tr><td><code>service.metricsPort</code></td><td><code>8080</code></td><td>Metrics port exposed by the Service.</td></tr><tr><td><code>healthProbeBindAddress</code></td><td><code>:8081</code></td><td>Health/readiness bind address used by the chart; passed to <code>--health-probe-bind-address</code> and overrides the binary default <code>:8090</code>.</td></tr><tr><td><code>certificates.create</code></td><td><code>false</code></td><td>When true, the chart renders cert-manager issuer and certificate resources.</td></tr></tbody></table><p>The Deployment runs the binary with <code>serve</code>, mounts serving certificates from <code>rebac-authz-webhook-cert</code> at <code>/config</code>, and exposes container ports <code>9443</code> (webhook server) and <code>8080</code> (metrics, also exposed by the Service).</p><h2 id="rbac-and-permissions" tabindex="-1">RBAC and permissions <a class="header-anchor" href="#rbac-and-permissions" aria-label="Permalink to &quot;RBAC and permissions&quot;">​</a></h2><p>The chart installs a <code>ClusterRole</code> bound to the webhook&#39;s <code>ServiceAccount</code> on the management cluster:</p><table tabindex="0"><thead><tr><th>API group</th><th>Resources</th><th>Verbs</th></tr></thead><tbody><tr><td><code>core.platform-mesh.io</code></td><td><code>accounts</code>, <code>accounts/status</code></td><td><code>get</code>, <code>list</code>, <code>watch</code></td></tr><tr><td>(core)</td><td><code>namespaces</code></td><td><code>get</code>, <code>list</code>, <code>watch</code></td></tr></tbody></table><p>All workspace-scoped reads (<code>LogicalCluster</code>, <code>Store</code>, <code>APIExportEndpointSlice</code>, dynamic REST mapping) go through the kcp kubeconfig mounted from <code>rebac-authz-webhook-kubeconfig</code>, not through the management-cluster <code>ClusterRole</code>.</p><h2 id="observability" tabindex="-1">Observability <a class="header-anchor" href="#observability" aria-label="Permalink to &quot;Observability&quot;">​</a></h2><p>The webhook exposes controller-runtime Prometheus metrics on <code>--metrics-bind-address</code> (binary default <code>:9090</code>). Standard controller-runtime metrics are exported, including reconcile counts, latencies, and workqueue depth.</p><p>OpenTelemetry instrumentation covers outgoing kcp HTTP calls and OpenFGA gRPC calls. Trace export is configured through standard <code>OTEL_*</code> environment variables, which can be supplied through the chart&#39;s <code>extraEnvs</code>.</p><p>Logging uses <code>klog</code> and the standard Kubernetes logging flags. The chart appends <span><code>--v={{ .Values.v }}</code></span> when <code>v</code> is set.</p><h2 id="tls-and-trust" tabindex="-1">TLS and trust <a class="header-anchor" href="#tls-and-trust" aria-label="Permalink to &quot;TLS and trust&quot;">​</a></h2><p>kcp calls the webhook over HTTPS, so it must trust the certificate served by <code>/authz</code>. That certificate is signed by an in-cluster CA. The <a href="./platform-mesh-operator.html">Platform Mesh operator</a> copies the matching CA bundle into the kubeconfig kcp uses for the webhook call.</p>',40)),(o(),c(n,null,{default:t(()=>[s(r,{id:"mermaid-685",class:"mermaid",graph:"sequenceDiagram%0A%20%20participant%20Op%20as%20platform-mesh-operator%0A%20%20participant%20CM%20as%20cert-manager%0A%20%20participant%20Sec%20as%20kcp-webhook-secret%0A%20%20participant%20Cert%20as%20rebac-authz-webhook-cert%0A%20%20participant%20KCP%20as%20kcp%20shard%0A%20%20participant%20Webhook%20as%20rebac-authz-webhook%0A%0A%20%20Op-%3E%3ECM%3A%20apply%20Issuer%20%2B%20Certificate%0A%20%20CM--%3E%3ECert%3A%20issue%20serving%20cert%20%2B%20ca.crt%0A%20%20Cert--%3E%3EWebhook%3A%20mount%20at%20%2Fconfig%0A%20%20Op-%3E%3ESec%3A%20write%20kubeconfig%20with%20certificate-authority-data%20from%20Cert%0A%20%20KCP-%3E%3ESec%3A%20load%20via%20authorization.webhook.configSecretName%0A%20%20KCP-%3E%3EWebhook%3A%20HTTPS%20POST%20%2Fauthz%2C%20validate%20cert%20against%20injected%20CA%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[d(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=a('<p>The webhook does not authenticate the caller itself. In the default setup, it relies on the in-cluster Service and serving certificate, and does not use client-certificate mTLS.</p><h2 id="deployment-and-platform-mesh-wiring" tabindex="-1">Deployment and Platform Mesh wiring <a class="header-anchor" href="#deployment-and-platform-mesh-wiring" aria-label="Permalink to &quot;Deployment and Platform Mesh wiring&quot;">​</a></h2><p>Platform Mesh installs the webhook through the <code>platform-mesh-operator-components</code> chart. The service entry is enabled by default:</p><table tabindex="0"><thead><tr><th>Value</th><th>Default</th></tr></thead><tbody><tr><td><code>services.rebac-authz-webhook.enabled</code></td><td><code>true</code></td></tr><tr><td><code>services.rebac-authz-webhook.values.openfga.url</code></td><td><code>openfga:8081</code></td></tr><tr><td><code>services.rebac-authz-webhook.values.certManager.enabled</code></td><td><code>true</code></td></tr><tr><td><code>services.rebac-authz-webhook.values.certManager.createCA</code></td><td><code>true</code></td></tr><tr><td><code>services.rebac-authz-webhook.imageResources[].annotations.for</code></td><td><code>rebac-authz-webhook</code></td></tr></tbody></table><p>The <code>infra</code> chart configures kcp to call the webhook:</p><table tabindex="0"><thead><tr><th>Value</th><th>Default</th></tr></thead><tbody><tr><td><code>kcp.webhook.enabled</code></td><td><code>true</code></td></tr><tr><td><code>kcp.webhook.server</code></td><td><code>https://rebac-authz-webhook.platform-mesh-system.svc.cluster.local:9443/authz</code></td></tr><tr><td><code>kcp.webhook.authorizationWebhookSecretName</code></td><td><code>kcp-webhook-secret</code></td></tr><tr><td><code>kcp.webhook.port</code></td><td><code>9443</code></td></tr><tr><td><code>kcp.webhook.version</code></td><td><code>v1</code></td></tr></tbody></table><p>The infra chart templates these values into the <code>RootShard</code> and <code>Shard</code> custom resources (<code>operator.kcp.io/v1alpha1</code>) under <code>spec.authorization.webhook.{configSecretName,version}</code>. The <a href="./kcp-operator.html">kcp-operator</a> reconciles those CRs into the running kcp shards.</p><p>At runtime, kcp loads <code>kcp-webhook-secret</code> and calls its <code>/authz</code> URL for authorization decisions. The CA bundle in that kubeconfig is filled in by the Platform Mesh operator, as described in <a href="#tls-and-trust">TLS and trust</a>. The chart&#39;s own <code>certificates.create</code> is left at <code>false</code> because the certificate is issued by the Platform Mesh operator.</p><h2 id="local-setup" tabindex="-1">Local setup <a class="header-anchor" href="#local-setup" aria-label="Permalink to &quot;Local setup&quot;">​</a></h2><p>For local setup, see <a href="/pr-preview/pr-188/how-to-guides/set-up-platform-mesh-locally.html">Set up Platform Mesh locally</a>. The webhook ships with the standard local stack and depends on OpenFGA and the Security operator being healthy before it can return useful authorization decisions.</p><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li><a href="https://github.com/platform-mesh/rebac-authz-webhook" target="_blank" rel="noreferrer">platform-mesh/rebac-authz-webhook</a></li><li><a href="https://github.com/platform-mesh/helm-charts/tree/main/charts/rebac-authz-webhook" target="_blank" rel="noreferrer">platform-mesh/helm-charts</a></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../../concepts/identity-and-authorization.html">Identity and authorization</a></li><li><a href="./openfga.html">OpenFGA</a></li><li><a href="./security-operator.html">Security operator</a></li><li><a href="./kcp/identity-and-authorization.html">kcp identity and authorization</a></li></ul>',14))])}const v=i(p,[["render",u]]);export{A as __pageData,v as default};
